import { describe, it, expect } from "vitest";

describe("BUG-001: Server does not validate history array structure", () => {
  it.fails("BUG-001: should reject history items missing content field", async () => {
    const { buildPrompt } = await import(
      "../server/src/lib/chat/prompt-builder.js"
    );
    // This should throw or produce malformed output — currently it passes through
    const result = buildPrompt({
      userMessage: "hello",
      history: [{ role: "user", content: undefined as any }],
      forms: [],
      userRole: "admin",
    });
    // The bug is that history items aren't validated upstream;
    // the prompt builder blindly passes them to the LLM API
    expect(result[1].content).toBeDefined();
  });
});

