describe("BUG-005: Ghost empty assistant message on send failure", () => {
  it.fails("BUG-005: should remove empty message on error", () => {
    const { useChatStore } = require("../client/src/stores/chat-store");
    const store = useChatStore.getState();

    // Simulate: add message, set error (like useChat does on failure)
    store.addMessage({
      id: "1",
      role: "user",
      content: "hello",
      timestamp: 100,
    });
    store.addMessage({
      id: "2",
      role: "assistant",
      content: "",
      timestamp: 101,
    });
    // On error, the current code sets error but doesn't remove the empty message
    store.setError("API error");

    const msgs = store.messages;
    // Bug: the empty assistant message (id: "2") is still in the list
    // It should have been removed or marked as failed
    const emptyAssistant = msgs.find(
      (m) => m.role === "assistant" && m.content === ""
    );
    expect(emptyAssistant).toBeUndefined();
  });
});

